changeSet.sql:
ALTER TABLE practice_finding DROP CONSTRAINT IF EXISTS chk_practice_finding_target_type;
ALTER TABLE practice_finding
ADD CONSTRAINT chk_practice_finding_target_type
CHECK (artifact_type IN ('PULL_REQUEST', 'ISSUE'));

changeSet.rollback:
ALTER TABLE practice_finding DROP CONSTRAINT IF EXISTS chk_practice_finding_target_type;
