ADD CONSTRAINT chk_practice_finding_target_type
CHECK (artifact_type IN ('PULL_REQUEST'));

changeSet.sql:
ALTER TABLE practice_finding DROP CONSTRAINT IF EXISTS chk_practice_finding_verdict;
UPDATE practice_finding SET verdict = 'PRESENT' WHERE verdict IN ('POSITIVE', 'OBSERVED');
UPDATE practice_finding SET verdict = 'ABSENT' WHERE verdict IN ('NEGATIVE', 'NOT_OBSERVED');
ALTER TABLE practice_finding ADD CONSTRAINT chk_practice_finding_verdict
    CHECK (verdict IN ('PRESENT', 'ABSENT', 'NOT_APPLICABLE'));

changeSet.rollback:
ALTER TABLE practice_finding DROP CONSTRAINT IF EXISTS chk_practice_finding_verdict;
UPDATE practice_finding SET verdict = 'POSITIVE' WHERE verdict = 'PRESENT';
UPDATE practice_finding SET verdict = 'NEGATIVE' WHERE verdict = 'ABSENT';
ALTER TABLE practice_finding ADD CONSTRAINT chk_practice_finding_verdict
    CHECK (verdict IN ('POSITIVE', 'NEGATIVE', 'NOT_APPLICABLE', 'NEEDS_REVIEW'));

